monthly_debt_payment=#{monthlyDebtPayment}, dti=#{dti}, foir=#{foir}, disposable_income=#{disposableIncome},
income_stability_score=#{incomeStabilityScore}, max_affordable_emi=#{maxAffordableEmi},
recommended_credit_limit=#{recommendedCreditLimit}, updated_at=#{updatedAt}
WHERE application_id=#{applicationId}
